import json
import hashlib
import hmac
import os
from flask import Flask, request, jsonify
from datetime import datetime, timedelta

app = Flask(__name__)

# Configuration
WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET')
ALLOWED_PARTNERS = set(os.environ.get('ALLOWED_PARTNERS', '').split(','))

def validate_signature(request, secret):
    """Validate webhook signature"""
    signature = request.headers.get('X-Signature')
    if not signature:
        return False
    
    payload = request.get_data()
    expected_signature = hmac.new(
        secret.encode(),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_partner(partner_id):
    """Validate partner is allowed"""
    return partner_id in ALLOWED_PARTNERS

def validate_request_timestamp(timestamp):
    """Validate request timestamp is within acceptable window"""
    try:
        request_time = datetime.fromisoformat(timestamp.replace('Z', '+00:00'))
        now = datetime.now(datetime.timezone.utc)
        time_diff = abs((now - request_time).total_seconds())
        return time_diff < 300  # 5 minutes window
    except:
        return False

@app.route('/webhook/payment', methods=['POST'])
def payment_webhook():
    try:
        # Get request data
        data = request.get_json()
        
        # Validate content type
        if not request.is_json:
            return jsonify({'error': 'Content-Type must be application/json'}), 400
        
        # Validate partner
        partner_id = data.get('partner_id')
        if not partner_id or not validate_partner(partner_id):
            return jsonify({'error': 'Unauthorized partner'}), 401
        
        # Validate timestamp
        timestamp = data.get('timestamp')
        if not timestamp or not validate_request_timestamp(timestamp):
            return jsonify({'error': 'Invalid timestamp'}), 400
        
        # Validate signature
        if not validate_signature(request, WEBHOOK_SECRET):
            return jsonify({'error': 'Invalid signature'}), 401
        
        # Process payment webhook
        event_type = data.get('event_type')
        payment_id = data.get('payment_id')
        status = data.get('status')
        
        # Log webhook receipt
        print(f"Processing webhook: {event_type} for payment {payment_id} with status {status}")
        
        # Add your payment processing logic here
        # Example: update database, send notifications, etc.
        
        return jsonify({'status': 'success', 'message': 'Webhook processed'}), 200
        
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

